import { readFile, writeFile } from "node:fs/promises";
import { resolve } from "node:path";

const repoRoot = resolve(import.meta.dirname, "..");
const packageDir = resolve(repoRoot, "packages/japanpost-react");
const docsDir = resolve(packageDir, "docs");
const englishPath = resolve(docsDir, "README.en.md");
const koreanPath = resolve(docsDir, "README.ko.md");
const outputPath = resolve(packageDir, "README.md");

const generatedNotice =
  "<!-- This file is generated by `pnpm readme:package`. Edit docs/README.en.md and docs/README.ko.md instead. -->";

async function loadTrimmed(path) {
  const content = await readFile(path, "utf8");
  return content.trim();
}

async function loadExisting(path) {
  try {
    return await readFile(path, "utf8");
  } catch (error) {
    if (
      typeof error === "object" &&
      error !== null &&
      "code" in error &&
      error.code === "ENOENT"
    ) {
      return null;
    }

    throw error;
  }
}

const [english, korean] = await Promise.all([
  loadTrimmed(englishPath),
  loadTrimmed(koreanPath),
]);

const output = [
  generatedNotice,
  "",
  "# @cp949/japanpost-react",
  "",
  "[English](#english) | [한국어](#한국어)",
  "",
  "---",
  "",
  "## English",
  "",
  english.replace(/^# .+\n*/, "").trim(),
  "",
  "---",
  "",
  "## 한국어",
  "",
  korean.replace(/^# .+\n*/, "").trim(),
  "",
].join("\n");

if (process.argv.includes("--check")) {
  const existing = await loadExisting(outputPath);

  if (existing !== output) {
    console.error(
      `Generated content does not match ${outputPath}. Run pnpm readme:package.`,
    );
    process.exit(1);
  }

  console.log(`Verified ${outputPath}`);
} else {
  await writeFile(outputPath, output);
  console.log(`Generated ${outputPath}`);
}
